import * as React from 'react';
import clsx from 'clsx';
import { useCssScope } from '../../config-provider/hooks';
import { __SCREENSHOT__ } from '../../util';
import './styles/SpinLoadingSvg.less';

const SCREENSHOT_PROPS = __SCREENSHOT__
  ? {
      style: {
        animationPlayState: 'paused',
      },
    }
  : {};

function SpinLoadingSvg(props: React.SVGProps<SVGSVGElement>, svgRef?: React.Ref<SVGSVGElement>) {
  const { className, ...restProps } = props;
  const cssScope = useCssScope('svg');
  const classes = clsx(cssScope(), cssScope('-spin-loading'), className);

  return (
    <div className={classes} {...SCREENSHOT_PROPS}>
      <svg width="100%" height="100%" viewBox="0 0 100 100" ref={svgRef} {...restProps}>
        <circle
          cx="50"
          cy="50"
          r="35"
          stroke="currentColor"
          strokeWidth="11"
          strokeLinecap="round"
          strokeMiterlimit="10"
          fill="none"
          {...SCREENSHOT_PROPS}
        />
      </svg>
    </div>
  );
}

const ForwardRef = React.forwardRef(SpinLoadingSvg);
export default ForwardRef;
